<template>
  <div>
    <my-header 
      :user="user" 
      :orders="orders"
      @clearUser="clearUser"
    />
    <my-nav />
    <div
      class="detail"
    >
      <div class="link_path">
        <div class="link_path_title">
          <span class="link_path_item">团购</span>&gt;
          <span class="link_path_item">{{ sortedText }}</span>&gt;
          <span class="link_path_item">{{ singlefoodlist.foot_name }}</span>
        </div>
      </div>
      <div class="link_path_detail">
        <div class="content">
          <div class="content_title">
            <h2>{{ singlefoodlist.foot_name }}</h2>
            <div class="title_introduce">
              仅售 {{ singlefoodlist.new_price }} 元,价值{{ singlefoodlist.old_price }}元的精选自助餐1位!免费wifi！
            </div>
          </div>
          <div class="content_detail">
            <div class="img_list">
              <div class="big_img">
                <img :src="singlefoodlist.img_list_first">
              </div>
              <div class="img_icon">
                <div 
                  class="img"
                >
                  <img :src="singlefoodlist.img_list_first">
                </div>
                <div 
                  class="img"
                >
                  <img :src="singlefoodlist.img_list_second">
                </div>
                <div 
                  class="img"
                >
                  <img :src="singlefoodlist.img_list_three">
                </div>
              </div>
            </div>
            <div class="production_detail">
              <div class="production_price">
                <span class="mark">￥</span>
                <span class="price">{{ singlefoodlist.special_price }}</span>
                <span 
                  class="top_icon"
                  v-show="singlefoodlist.special_price <= singlefoodlist.new_price"
                >优惠价</span>
                <div class="group_price">
                  <del class="oldPrice">￥{{ singlefoodlist.new_price }}</del>
                  <div class="group_txt">
                    团购价
                  </div>
                </div>
                <div class="has_price">
                  <del class="has_Price">￥{{ singlefoodlist.old_price }}</del>
                  <div class="has_txt">
                    价值
                  </div>
                </div>
              </div>
              <div class="timer_container">
                <span class="price_point">
                  {{ singlefoodlist.special_price }}元
                </span>
                <span class="has_time">
                  距结束时间还有
                  <span class="time_commen hours">18</span>时
                  <span class="time_commen minutes">20</span>分
                  <span class="time_commen seconds">10</span>秒
                </span>
                <span class="more">
                  更多精选品牌特惠&gt;
                </span>
              </div>
              <div class="has_buy">
                {{ singlefoodlist.foot_sold }} 人已团购
              </div>
              <div class="time_inner">
                <span>有效期</span>
                <span class="timer_inner_detail">{{ timeend }}</span>
              </div>
              <div class="num_content">
                <span>数量</span>
                <el-input-number
                  v-model="num"
                  :min="1" 
                  size="mini"
                  class="el_input_number"
                  label="商品购买数量"
                />
                <span class="has_num">
                  优惠价剩余{{ singlefoodlist.hasgoods }}份
                </span>
              </div>
              <div 
                class="buy"
                @click.stop="pay"
              >
                立即购买
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
    <my-link />
    <my-footer />
  </div>
</template>
<script>
import myHeader from "./header.vue";
import myFooter from "../commen/components/footer.vue";
import myNav from "./nav.vue";
import myLink from "./link.vue";
import api from "../api/singleshop/api.js";
import listApi  from "../api/list/api.js";
import store from "../store/index";
export default {
    data (){
        return {
            // 单个商品数据
            singlefoodlist:"",
            // 剩余时间
            timeend:"",
            // 商品所属分类
            sortedText:"",
            // 用户登陆信息
            user:{},
            // 用户订单数
            orders:0

        };
    },
    created (){
        this.getProductionDetailInformation();
        this.getSorted();
        this.getUser();
        this.getUserOrders();


    },
    computed:{
        num :{
            get (){
                return this.$store.state.num;
            },
            set (num){
                this.$store.commit("setGoodsNum",num);

            }
        }
        

    },
    components:{
        myHeader,
        myNav,
        myLink,
        myFooter

    },
    methods:{
        // 获取用户信息
        getUser (){
            this.axios.get(`${listApi.user}`).then(response => {
                if(response.code === 200){
                    this.user = response.data;
                }
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        // 获取用户订单数
        getUserOrders (){
            this.axios.get(listApi.orders).then(response => {
                if(response.code === 200){

                    this.orders = response.data.order_num;
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        // 用户推出
        clearUser (){
            this.user = { };
            this.orders = 0;

        },
        // 获取列表数据详细信息
        getProductionDetailInformation (){
            let pid = this.$route.params.currentElementPid,
                id = this.$route.params.currentElementId;
            this.axios.get(`${api.singleShop}/${pid}/${id}`).then(response => {
                this.singlefoodlist = response.data;
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        /**
         * 获取商品所属分类
         */
        getSorted (){
            const pid = this.$route.params.currentElementPid;
            this.axios.get(`${listApi.sorted}/${pid}`).then(response => {
                if(response.code === 200){
                    this.sortedText = response.data.sorted_text;
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        /**
         * 购买商品
         */
        pay (){
            const pid = this.$route.params.currentElementPid,
                id = this.$route.params.currentElementId;
            this.$router.push({
                path:"/pay"
            });
            if(store.state.token || localStorage.getItem("token")){
                this.axios.post(`${listApi.order}`,{
                // 商品名
                    foodName: this.singlefoodlist.foot_name,
                    // 商品图片
                    foodImg :this.singlefoodlist.foot_img,
                    // 商品备注
                    foodNotice:this.singlefoodlist.foot_notice,
                    // 商品优惠价
                    reducePrice:this.singlefoodlist.reduce_price,
                    // 商品价格
                    price:this.singlefoodlist.new_price,
                    // 商品数量
                    num : this.num,
                    // 商品的编号id
                    shopid : id,
                    // 商品所属的类别
                    shoppid : pid
                }).then(response => {
                    console.log(response);
                    return ;
                }).catch(error => {
                    console.log(error);
                });

            }
            

        }
        
    }
};
</script>
<style lang="scss" scoped>
.detail {
  .link_path {
    $height:50px;
    height: $height;
    line-height: $height;
    border-bottom: 1px dashed rgb(149, 149, 149);
    .link_path_title {
      width: 1000px;
      margin: 0 auto;
      font-size: 16px;
      .link_path_item {
        margin-left: 5px;
        &:first-child {
          margin: 0;
        }
        &:last-child {
          color: rgb(228, 0, 127);
        }
      }
    }
  }
  .link_path_detail {
    width: 100%;
    border-bottom: 1px solid rgb(149,149,149);
    box-shadow: 0 1px 2px 0 rgba(149,149,149,0.5);
    padding-bottom:30px;
    .content {
      width: 1000px;
      margin: 0 auto;
      .content_title{
          margin-top:10px;
          .title_introduce{
              height:40px;
              line-height:40px;
              color:rgb(149,149,149);
          }
      }
      .content_detail{
          margin-top:10px;
          position:relative;
          .img_list{
              width:45%;
              .big_img{
                  width:100%;
                  height:240px;
                  img{
                      width:100%;
                      height:100%;
                  }

              }
              .img_icon{
                  overflow:hidden;
                  margin-top:20px;
                  .img{
                      width: 110px;
                      height:70px;
                      float:left;
                      margin-left:15px;
                      position:relative;
                      cursor: pointer;
                      padding:1px;
                      border:1px solid transparent;
                      transition: all 0.1s ease-out;
                      &:hover{
                          border:1px solid rgb(228, 0, 127);
                      }
                      &:first-child{
                          margin:0;
                      }

                      img{
                          width:100%;
                          height:100%;
                      }
                  }
              }

          }
          .production_detail{
              width:50%;
              position: absolute;;
              top:0;
              left:48%;
              background-color:whitesmoke;
              font-size:14px;
              color:rgb(149,149,149);
              .production_price{
                  position:relative;
                  .mark,.price{
                      color:rgb(243,152,0);
                  }
                  .mark{
                      font-size:20px;
                  }
