                      }
                  }

              }
              .timer_container{
                  background-color:rgb(235, 104, 119);
                  color:white;
                  padding:5px 10px;
                  margin-top:5px;
                  .price_point{
                      color:rgb(235, 104, 119);
                      height:30px;
