                      }
                  }
                  .more{
                      margin-left:20px;
                  }
              }
              .has_buy{
                  height:80px;
                  border-bottom:1px dashed rgb(149,149,149);
                  line-height:80px;
                  padding-left:30px;
                  position:relative;
                  &::after{
                      content:"";
                      position:absolute;
                      left:200px;
