                      border-right:1px solid rgb(125,125,125);

                  }

              }
              .time_inner{
                  height:35px;
                  line-height:35px;
                  position:relative;
                  .timer_inner_detail{
                      position:absolute;
                      left:80px;
                  }

              }
              .num_content{
                  height:35px;
                  line-height:35px;
                  position:relative;
                  .el_input_number{
                    margin-left:14px;
                  }
                  .num{
                      position:absolute;
                      top:-5px;
                      left:80px;
                      font-size:0;
                      .reduce,.add{
                          position:absolute;
                          top:10px;
                          width:25px;
                          height:25px;
                          font-size:25px;
                          text-align:center;
                          line-height:20px;
                          box-sizing: border-box;
                          display:inline-block;
                          user-select:none;
                          border:1px solid rgba(149,149,149,1);
                          cursor: pointer;
                          &:hover{
                              color:rgb(228, 0, 127);
                              border:1px solid rgb(228, 0, 127);

                          }
                      }
                      .add{
                          left:77px;
                      }

                      .input_txt{
                          width:50px;
                          height:21px;
                          position:absolute;
                          top:10px;
                          left:25px;
                          outline:none;
                          text-align: center;
                          font-size:14px;
                      }
                  }
                  .has_num{
                      position:absolute;
                      left:200px;
                  }

              }
              .buy{
                  $height:55px;
                  background-color:rgb(243,152,0);
                  width:190px;
                  height:$height;
                  font-size:25px;
                  line-height:$height;
                  text-align:center;
                  color:whitesmoke;
                  margin-top:30px;
                  cursor: pointer;
              }
          }

      }
    }
  }
}
</style>


